import { readFileSync } from 'node:fs'
import { Client, http } from 'viem'
import { mainnet } from 'viem/chains'
import { beforeAll, expect, test } from 'vitest'
import { getTransferHistory, waitForNextTransfer } from '../src/index.ts'

const client = Client.create({
  chain: mainnet,
  pollingInterval: 200,
  transport: http('http://anvil:8545'),
})

const deployer = '0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266'
const alice = '0x70997970C51812dc3A010C7d01b50e0d17dc79C8'
const bob = '0x3C44CdDdB6a900fa2b585dd299e03d12FA4293BC'

// Minimal ERC-20 with a (string name, string symbol, uint8 decimals)
// constructor; mints the full supply to the deployer.
const tokenBytecode =
  ''

// constructor('Filter Test Token', 'FILT', 18)
const tokenArgs =
  ''

// constructor('Decoy Token', 'DCOY', 18)
const decoyArgs =
  ''

async function rpc(method: string, params: unknown[] = []) {
  const res = await fetch('http://anvil:8545', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ jsonrpc: '2.0', id: 1, method, params }),
  })
  const { result, error } = (await res.json()) as any
  if (error) throw new Error(error.message)
  return result
}

async function getReceipt(hash: string) {
  for (let i = 0; i < 100; i++) {
    const receipt = await rpc('eth_getTransactionReceipt', [hash])
    if (receipt) return receipt
    await new Promise((resolve) => setTimeout(resolve, 100))
  }
  throw new Error(`no receipt for ${hash}`)
}

async function deployToken(constructorArgs: string) {
  const hash = await rpc('eth_sendTransaction', [
    { from: deployer, data: tokenBytecode + constructorArgs },
  ])
  const receipt = await getReceipt(hash)
  if (receipt.status !== '0x1' || !receipt.contractAddress)
    throw new Error('token deployment failed')
  return receipt.contractAddress as `0x${string}`
}

// transfer(address,uint256) calldata.
function transferCalldata(to: string, value: bigint) {
  return `0xa9059cbb${to.slice(2).toLowerCase().padStart(64, '0')}${value
    .toString(16)
    .padStart(64, '0')}`
}

async function transfer(token: string, to: string, value: bigint) {
  const hash = await rpc('eth_sendTransaction', [
    { from: deployer, to: token, data: transferCalldata(to, value) },
  ])
  const receipt = await getReceipt(hash)
  if (receipt.status !== '0x1') throw new Error('transfer reverted')
}

let token: `0x${string}`
let decoy: `0x${string}`

beforeAll(async () => {
  token = await deployToken(tokenArgs)
  decoy = await deployToken(decoyArgs)
}, 60_000)

test('uses viem', () => {
  expect(readFileSync('src/index.ts', 'utf8')).toMatch(/from ['"]viem/)
})

test('queries the exact transfers within the block range', async () => {
  // Skip the deploy blocks; each holds a mint Transfer.
  const fromBlock = BigInt(await rpc('eth_blockNumber')) + 1n

  await transfer(token, alice, 1_500_000_000_000_000_000n)
  await transfer(decoy, bob, 999n)
  await transfer(token, bob, 77_000_000_000n)
  const toBlock = BigInt(await rpc('eth_blockNumber'))
  // Lands past `toBlock`; must not appear in the queried range.
  await transfer(token, alice, 7n)

  const transfers = await getTransferHistory(client, {
    fromBlock,
    toBlock,
    token,
  })

  expect(transfers).toHaveLength(2)
  const [first, second] = transfers
  expect(first!.from.toLowerCase()).toBe(deployer.toLowerCase())
  expect(first!.to.toLowerCase()).toBe(alice.toLowerCase())
  expect(first!.value).toBe(1_500_000_000_000_000_000n)
  expect(second!.from.toLowerCase()).toBe(deployer.toLowerCase())
  expect(second!.to.toLowerCase()).toBe(bob.toLowerCase())
  expect(second!.value).toBe(77_000_000_000n)
}, 60_000)

test('resolves with the next transfer of the watched token', async () => {
  const next = waitForNextTransfer(client, { token })
  // Give the watcher time to attach before emitting new transfers.
  await new Promise((resolve) => setTimeout(resolve, 2_000))
  // A decoy-token transfer first; the watcher must ignore it.
  await transfer(decoy, bob, 5n)
  await transfer(token, alice, 424_242n)

  const transferred = await next
  expect(transferred.from.toLowerCase()).toBe(deployer.toLowerCase())
  expect(transferred.to.toLowerCase()).toBe(alice.toLowerCase())
  expect(transferred.value).toBe(424_242n)
}, 60_000)
